import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';

interface Vara {
  id: number;
  nome: string;
}

interface Juiz {
  id: number;
  nome: string;
}

interface Promotor {
  id: number;
  nome: string;
}

interface Pessoa {
  id: number;
  nome: string;
  cpf: string;
  email: string;
}

interface Advogado {
  id: number;
  nome: string;
  oab: string;
}

interface ParticipanteForm {
  pessoaId: number;
  tipo: string;
  intimado: boolean;
  observacoes: string;
  advogadoId?: number;
  tipoRepresentacao?: string;
}

interface AudienciaForm {
  data: string;
  hora: string;
  status: string;
  varaId: number;
  juizId: number;
  promotorId: number;
  processo: string;
  sala: string;
  observacoes: string;
}

const FormAudiencia: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const isEdicao = !!id;

  const [formData, setFormData] = useState<AudienciaForm>({
    data: '',
    hora: '',
    status: 'AGENDADA',
    varaId: 0,
    juizId: 0,
    promotorId: 0,
    processo: '',
    sala: '',
    observacoes: ''
  });

  const [varas, setVaras] = useState<Vara[]>([]);
  const [juizes, setJuizes] = useState<Juiz[]>([]);
  const [promotores, setPromotores] = useState<Promotor[]>([]);
  const [pessoas, setPessoas] = useState<Pessoa[]>([]);
  const [advogados, setAdvogados] = useState<Advogado[]>([]);
  const [participantes, setParticipantes] = useState<ParticipanteForm[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [submitting, setSubmitting] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchDados = async () => {
      try {
        setLoading(true);

        // Carregar listas de varas, juízes, promotores, pessoas e advogados
        const [varasRes, juizesRes, promotoresRes, pessoasRes, advogadosRes] = await Promise.all([
          axios.get<Vara[]>('/api/varas'),
          axios.get<Juiz[]>('/api/juizes'),
          axios.get<Promotor[]>('/api/promotores'),
          axios.get<Pessoa[]>('/api/pessoas'),
          axios.get<Advogado[]>('/api/advogados')
        ]);

        setVaras(varasRes.data);
        setJuizes(juizesRes.data);
        setPromotores(promotoresRes.data);
        setPessoas(pessoasRes.data);
        setAdvogados(advogadosRes.data);

        // Se for edição, carregar dados da audiência
        if (isEdicao) {
          const audienciaRes = await axios.get(`/api/audiencias/${id}`);
          const audiencia = audienciaRes.data;

          setFormData({
            data: audiencia.data.split('T')[0], // Formato YYYY-MM-DD
            hora: audiencia.hora,
            status: audiencia.status,
            varaId: audiencia.vara.id,
            juizId: audiencia.juiz.id,
            promotorId: audiencia.promotor.id,
            processo: audiencia.processo,
            sala: audiencia.sala,
            observacoes: audiencia.observacoes || ''
          });

          // Carregar participantes da audiência
          const participantesRes = await axios.get(`/api/audiencias/${id}/participantes`);
          const participantesData = participantesRes.data.map((p: any) => ({
            pessoaId: p.pessoa.id,
            tipo: p.tipo,
            intimado: p.intimado,
            observacoes: p.observacoes || '',
            advogadoId: p.representacao?.advogado?.id || undefined,
            tipoRepresentacao: p.representacao?.tipo || undefined
          }));
          setParticipantes(participantesData);
        }

        setError(null);
      } catch (err) {
        setError('Erro ao carregar dados. Por favor, tente novamente.');
        console.error('Erro ao buscar dados:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchDados();
  }, [id, isEdicao]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const adicionarParticipante = () => {
    setParticipantes(prev => [...prev, {
      pessoaId: 0,
      tipo: 'AUTOR',
      intimado: false,
      observacoes: '',
      advogadoId: undefined,
      tipoRepresentacao: undefined
    }]);
  };

  const removerParticipante = (index: number) => {
    setParticipantes(prev => prev.filter((_, i) => i !== index));
  };

  const handleParticipanteChange = (index: number, field: keyof ParticipanteForm, value: any) => {
    setParticipantes(prev => prev.map((p, i) => 
      i === index ? { ...p, [field]: value } : p
    ));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      setSubmitting(true);
      setError(null);

      const payload = {
        ...formData,
        varaId: Number(formData.varaId),
        juizId: Number(formData.juizId),
        promotorId: Number(formData.promotorId)
      };

      let audienciaId: string;

      if (isEdicao) {
        await axios.put(`/api/audiencias/${id}`, payload);
        audienciaId = id!;
      } else {
        const response = await axios.post('/api/audiencias', payload);
        audienciaId = response.data.id;
      }

      // Salvar participantes
      if (participantes.length > 0) {
        const participantesPayload = participantes
          .filter(p => p.pessoaId > 0)
          .map(p => ({
            pessoaId: Number(p.pessoaId),
            tipo: p.tipo,
            intimado: p.intimado,
            observacoes: p.observacoes,
            advogadoId: p.advogadoId ? Number(p.advogadoId) : undefined,
            tipoRepresentacao: p.tipoRepresentacao
          }));

        if (isEdicao) {
          // Remover participantes existentes e adicionar novos
          await axios.delete(`/api/audiencias/${audienciaId}/participantes`);
        }

        for (const participante of participantesPayload) {
          await axios.post(`/api/audiencias/${audienciaId}/participantes`, participante);
        }
      }

      navigate('/audiencias');
    } catch (err: any) {
      setError(err.response?.data?.message || 'Erro ao salvar audiência. Por favor, tente novamente.');
      console.error('Erro ao salvar audiência:', err);
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-900"></div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <h1 className="text-2xl font-bold text-gray-800 mb-6">
        {isEdicao ? 'Editar Audiência' : 'Nova Audiência'}
      </h1>

      {error && (
        <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded relative mb-4" role="alert">
          <strong className="font-bold">Erro!</strong>
          <span className="block sm:inline"> {error}</span>
        </div>
      )}

      <form onSubmit={handleSubmit} className="bg-white shadow-md rounded px-8 pt-6 pb-8 mb-4">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2" htmlFor="processo">
              Número do Processo*
            </label>
            <input
              className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
              id="processo"
              name="processo"
              type="text"
              placeholder="0000000-00.0000.0.00.0000"
              value={formData.processo}
              onChange={handleChange}
              required
            />
          </div>

          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2" htmlFor="data">
              Data*
            </label>
            <input
              className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
              id="data"
              name="data"
              type="date"
              value={formData.data}
              onChange={handleChange}
              required
            />
          </div>

          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2" htmlFor="hora">
              Hora*
            </label>
            <input
              className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
              id="hora"
              name="hora"
              type="time"
              value={formData.hora}
              onChange={handleChange}
              required
            />
          </div>

          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2" htmlFor="sala">
              Sala*
            </label>
            <input
              className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
              id="sala"
              name="sala"
              type="text"
              placeholder="Sala de Audiência"
              value={formData.sala}
              onChange={handleChange}
              required
            />
          </div>

          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2" htmlFor="status">
              Status*
            </label>
            <select
              className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
              id="status"
              name="status"
              value={formData.status}
              onChange={handleChange}
              required
            >
              <option value="AGENDADA">Agendada</option>
              <option value="REALIZADA">Realizada</option>
              <option value="CANCELADA">Cancelada</option>
              <option value="ADIADA">Adiada</option>
            </select>
          </div>

          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2" htmlFor="varaId">
              Vara*
            </label>
            <select
              className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
              id="varaId"
              name="varaId"
              value={formData.varaId}
              onChange={handleChange}
              required
            >
              <option value="">Selecione uma vara</option>
              {varas.map(vara => (
                <option key={vara.id} value={vara.id}>{vara.nome}</option>
              ))}
            </select>
          </div>

          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2" htmlFor="juizId">
              Juiz*
            </label>
            <select
              className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
              id="juizId"
              name="juizId"
              value={formData.juizId}
              onChange={handleChange}
              required
            >
              <option value="">Selecione um juiz</option>
              {juizes.map(juiz => (
                <option key={juiz.id} value={juiz.id}>{juiz.nome}</option>
              ))}
            </select>
          </div>

          <div className="mb-4">
            <label className="block text-gray-700 text-sm font-bold mb-2" htmlFor="promotorId">
              Promotor*
            </label>
            <select
              className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
              id="promotorId"
              name="promotorId"
              value={formData.promotorId}
              onChange={handleChange}
              required
            >
              <option value="">Selecione um promotor</option>
              {promotores.map(promotor => (
                <option key={promotor.id} value={promotor.id}>{promotor.nome}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="mb-6">
          <label className="block text-gray-700 text-sm font-bold mb-2" htmlFor="observacoes">
            Observações
          </label>
          <textarea
            className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
            id="observacoes"
            name="observacoes"
            rows={4}
            placeholder="Observações sobre a audiência"
            value={formData.observacoes}
            onChange={handleChange}
          />
        </div>

        <div className="mb-6">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-lg font-bold text-gray-800">Participantes</h3>
            <button
              type="button"
              onClick={adicionarParticipante}
              className="bg-green-600 hover:bg-green-700 text-white font-bold py-2 px-4 rounded focus:outline-none focus:shadow-outline"
            >
              Adicionar Participante
            </button>
          </div>

          {participantes.map((participante, index) => (
            <div key={index} className="border border-gray-300 rounded p-4 mb-4">
              <div className="flex justify-between items-center mb-4">
                <h4 className="text-md font-semibold text-gray-700">Participante {index + 1}</h4>
                <button
                  type="button"
                  onClick={() => removerParticipante(index)}
                  className="bg-red-600 hover:bg-red-700 text-white font-bold py-1 px-3 rounded focus:outline-none focus:shadow-outline"
                >
                  Remover
                </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-gray-700 text-sm font-bold mb-2">
                    Pessoa*
                  </label>
                  <select
                    className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
                    value={participante.pessoaId}
                    onChange={(e) => handleParticipanteChange(index, 'pessoaId', Number(e.target.value))}
                    required
                  >
                    <option value="">Selecione uma pessoa</option>
                    {pessoas.map(pessoa => (
                      <option key={pessoa.id} value={pessoa.id}>
                        {pessoa.nome} - {pessoa.cpf}
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-gray-700 text-sm font-bold mb-2">
                    Tipo*
                  </label>
                  <select
                    className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
                    value={participante.tipo}
                    onChange={(e) => handleParticipanteChange(index, 'tipo', e.target.value)}
                    required
                  >
                    <option value="AUTOR">Autor</option>
                    <option value="REU">Réu</option>
                    <option value="TESTEMUNHA">Testemunha</option>
                    <option value="PERITO">Perito</option>
                    <option value="TERCEIRO">Terceiro</option>
                  </select>
                </div>

                <div>
                  <label className="block text-gray-700 text-sm font-bold mb-2">
                    Advogado
                  </label>
                  <select
                    className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
                    value={participante.advogadoId || ''}
                    onChange={(e) => handleParticipanteChange(index, 'advogadoId', e.target.value ? Number(e.target.value) : undefined)}
                  >
                    <option value="">Sem advogado</option>
                    {advogados.map(advogado => (
                      <option key={advogado.id} value={advogado.id}>
                        {advogado.nome} - OAB: {advogado.oab}
                      </option>
                    ))}
                  </select>
                </div>

                {participante.advogadoId && (
                  <div>
                    <label className="block text-gray-700 text-sm font-bold mb-2">
                      Tipo de Representação
                    </label>
                    <select
                      className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
                      value={participante.tipoRepresentacao || ''}
                      onChange={(e) => handleParticipanteChange(index, 'tipoRepresentacao', e.target.value)}
                    >
                      <option value="">Selecione o tipo</option>
                      <option value="CONSTITUIDO">Constituído</option>
                      <option value="DATIVO">Dativo</option>
                      <option value="AD_HOC">Ad Hoc</option>
                    </select>
                  </div>
                )}

                <div className="flex items-center">
                  <input
                    type="checkbox"
                    id={`intimado-${index}`}
                    checked={participante.intimado}
                    onChange={(e) => handleParticipanteChange(index, 'intimado', e.target.checked)}
                    className="mr-2"
                  />
                  <label htmlFor={`intimado-${index}`} className="text-gray-700 text-sm font-bold">
                    Intimado
                  </label>
                </div>
              </div>

              <div className="mt-4">
                <label className="block text-gray-700 text-sm font-bold mb-2">
                  Observações
                </label>
                <textarea
                  className="shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"
                  rows={2}
                  placeholder="Observações sobre o participante"
                  value={participante.observacoes}
                  onChange={(e) => handleParticipanteChange(index, 'observacoes', e.target.value)}
                />
              </div>
            </div>
          ))}
        </div>

        <div className="flex items-center justify-between">
          <button
            className="bg-gray-500 hover:bg-gray-700 text-white font-bold py-2 px-4 rounded focus:outline-none focus:shadow-outline"
            type="button"
            onClick={() => navigate('/audiencias')}
          >
            Cancelar
          </button>
          <button
            className="bg-blue-900 hover:bg-blue-800 text-white font-bold py-2 px-4 rounded focus:outline-none focus:shadow-outline"
            type="submit"
            disabled={submitting}
          >
            {submitting ? 'Salvando...' : 'Salvar'}
          </button>
        </div>
      </form>
    </div>
  );
};

export default FormAudiencia;
